ALTER TABLE "policies" ADD CONSTRAINT "policies_source_relative" CHECK ("policies"."source_path" <> '' and "policies"."source_path" not like '/%' and "policies"."source_path" not like '%/' and "policies"."source_path" not like '%//%' and "policies"."source_path" <> '.' and "policies"."source_path" not like './%' and "policies"."source_path" not like '%/.' and "policies"."source_path" not like '%/./%' and "policies"."source_path" <> '..' and "policies"."source_path" not like '../%' and "policies"."source_path" not like '%/..' and "policies"."source_path" not like '%/../%' and position(chr(92) in "policies"."source_path") = 0 and "policies"."source_path" !~ '[[:cntrl:]]');--> statement-breakpoint
ALTER TABLE "projects" ADD CONSTRAINT "projects_default_branch_not_option" CHECK ("projects"."default_branch" <> '' and "projects"."default_branch" not like '-%' and "projects"."default_branch" !~ '[[:cntrl:]]');